using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_WithItems_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_WithItems_SetsTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
        }

        [TestMethod]
        public void Constructor_WithItems_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list);
        }

        [TestMethod]
        public void Constructor_WithEmptyItems_CreatesEmptyList()
        {
            var items = new List<int>();
            var list = new PaginatedList<int>(items, 0, 1, 10);

            Assert.AreEqual(0, list.Count);
            Assert.AreEqual(0, list.TotalPages);
        }

        [TestMethod]
        [DataRow(1, false)]
        [DataRow(2, true)]
        [DataRow(3, true)]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true)]
        [DataRow(2, 3, true)]
        [DataRow(3, 3, false)]
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);
            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 10);
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 10);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void TotalPages_ExactDivision_ReturnsCorrectCount()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
            Assert.AreEqual(4, list.TotalPages); // 20/5 = 4
        }

        [TestMethod]
        public void TotalPages_NonExactDivision_RoundsUp()
        {
            var list = new PaginatedList<int>(new List<int>(), 21, 1, 5);
            Assert.AreEqual(5, list.TotalPages); // ceil(21/5) = 5
        }

        [TestMethod]
        public void TotalPages_SingleItem_ReturnsOne()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
            Assert.AreEqual(1, list.TotalPages);
        }
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void Setup()
        {
            _service = new NotificationService();
            // Drain the static queue to isolate tests
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _service?.Dispose();
        }

        [TestMethod]
        public void SendNotification_Create_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_GeneratesMessageWithId()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_Update_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Course 'Math 101' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_Delete_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateWithoutDisplayName_GeneratesMessageWithId()
        {
            _service.SendNotification("Course", "101", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Course (ID: 101) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteWithoutDisplayName_GeneratesMessageWithId()
        {
            _service.SendNotification("Department", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Department (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedByToSystem_WhenNoUserName()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedBy_WhenUserNameProvided()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("admin", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();

            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _service.ReceiveNotification();
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleNotifications_ReturnsFIFO()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("Course", second.EntityType);
            Assert.AreEqual("Department", third.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.IsNotNull(first);
            Assert.IsNull(second);
        }

        [TestMethod]
        public void SendNotification_QueueOverflow_EnforcesMaxLimit()
        {
            // Fill beyond max (500)
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            // Count remaining notifications
            int count = 0;
            while (_service.ReceiveNotification() != null) { count++; }

            Assert.IsTrue(count <= 500, $"Queue should not exceed 500 items but had {count}");
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op, should not throw
            _service.MarkAsRead(1);
            _service.MarkAsRead(0);
            _service.MarkAsRead(-1);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            _service.Dispose();
            // Should not throw even if called multiple times
            _service.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "1", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.IsFalse(notification.IsRead);
        }
    }
}

