using System;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Newtonsoft.Json;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;
        private NotificationService _helperService;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _helperService = new NotificationService();
            // Drain the queue
            while (_helperService.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            _helperService?.Dispose();
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            var json = result.Value;
            Assert.IsNotNull(json);
            // Check the anonymous object has success=true
            var successProp = json.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.IsTrue((bool)successProp.GetValue(json));

            var countProp = json.GetType().GetProperty("count");
            Assert.AreEqual(0, (int)countProp.GetValue(json));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            _helperService.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            _helperService.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();
            var json = result.Value;

            var countProp = json.GetType().GetProperty("count");
            Assert.IsTrue((int)countProp.GetValue(json) >= 1);
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10()
        {
            for (int i = 0; i < 15; i++)
            {
                _helperService.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            var json = result.Value;

            var countProp = json.GetType().GetProperty("count");
            Assert.IsTrue((int)countProp.GetValue(json) <= 10);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);
            var json = result.Value;

            var successProp = json.GetType().GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(json));
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void GetNotifications_RemovesFromQueue()
        {
            _helperService.SendNotification("Student", "1", EntityOperation.CREATE);

            // First call should get the notification
            var result1 = _controller.GetNotifications();
            var json1 = result1.Value;
            var count1 = (int)json1.GetType().GetProperty("count").GetValue(json1);

            // Second call should have nothing (or fewer)
            var result2 = _controller.GetNotifications();
            var json2 = result2.Value;
            var count2 = (int)json2.GetType().GetProperty("count").GetValue(json2);

            Assert.IsTrue(count1 >= 1);
            Assert.AreEqual(0, count2);
        }
    }
}

