using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_WithItems_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_WithItems_SetsTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
        }

        [TestMethod]
        public void Constructor_WithItems_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list);
        }

        [TestMethod]
        public void Constructor_WithEmptyItems_CreatesEmptyList()
        {
            var items = new List<int>();
            var list = new PaginatedList<int>(items, 0, 1, 10);

            Assert.AreEqual(0, list.Count);
            Assert.AreEqual(0, list.TotalPages);
        }

        [TestMethod]
        [DataRow(1, false)]
        [DataRow(2, true)]
        [DataRow(3, true)]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true)]
        [DataRow(2, 3, true)]
        [DataRow(3, 3, false)]
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);
            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 10);
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 10);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void TotalPages_ExactDivision_ReturnsCorrectCount()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
            Assert.AreEqual(4, list.TotalPages); // 20/5 = 4
        }

        [TestMethod]
        public void TotalPages_NonExactDivision_RoundsUp()
        {
            var list = new PaginatedList<int>(new List<int>(), 21, 1, 5);
            Assert.AreEqual(5, list.TotalPages); // ceil(21/5) = 5
        }

        [TestMethod]
        public void TotalPages_SingleItem_ReturnsOne()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
            Assert.AreEqual(1, list.TotalPages);
        }
    }
}

