+        {
+            _context = TestHelper.CreateInMemoryContext();
+            _controller = new NotificationsController(_context);
+            _helperService = new NotificationService();
+            // Drain the queue
+            while (_helperService.ReceiveNotification() != null) { }
+        }
+
